from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build a map of all subjects to their triples
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main building (subject with most triples or first one)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))
    main_triples = subject_triples[main_subject]

    # Collect all information into a coherent structure
    building_info = []

    # Start with the building name
    building_info.append(main_subject)

    # Add building type if available
    type_triple = next((t for t in main_triples if t.predicate == "buildingType"), None)
    if type_triple:
        building_info.append(f"is a {type_triple.object}")

    # Add design information (architect, style, owner, developer)
    architect_triple = next((t for t in main_triples if t.predicate == "architect"), None)
    style_triple = next((t for t in main_triples if t.predicate == "architecturalStyle"), None)
    owner_triple = next((t for t in main_triples if t.predicate == "owner"), None)
    developer_triple = next((t for t in main_triples if t.predicate == "developer"), None)

    design_parts = []
    if architect_triple:
        design_parts.append(f"designed by {architect_triple.object}")
    if style_triple:
        design_parts.append(f"with {style_triple.object} architectural style")
    if owner_triple:
        design_parts.append(f"owned by {owner_triple.object}")
    if developer_triple:
        design_parts.append(f"developed by {developer_triple.object}")

    if design_parts:
        building_info.append(f"which was " + ", ".join(design_parts))

    # Add location information (handle hierarchical relationships)
    location_parts = []
    location_triples = [t for t in main_triples if t.predicate in ["location", "address"]]
    country_triple = next((t for t in main_triples if t.predicate == "country"), None)
    state_triple = next((t for t in main_triples if t.predicate == "state"), None)
    region_triple = next((t for t in main_triples if t.predicate == "region"), None)

    if location_triples:
        for t in location_triples:
            if t.predicate == "location":
                location_parts.append(f"located at {t.object}")
            elif t.predicate == "address":
                location_parts.append(f"at address {t.object}")

    if state_triple:
        location_parts.append(f"in {state_triple.object}")
    if region_triple:
        location_parts.append(f"within {region_triple.object}")
    if country_triple:
        location_parts.append(f"in {country_triple.object}")

    if location_parts:
        building_info.append(", ".join(location_parts))

    # Add construction information
    const_parts = []
    for t in main_triples:
        if t.predicate == "completionDate":
            const_parts.append(f"completed in {t.object}")
        elif t.predicate in ["buildingStartDate", "yearOfConstruction"]:
            const_parts.append(f"built in {t.object}")
        elif t.predicate == "inaugurationDate":
            const_parts.append(f"inaugurated on {t.object}")
        elif t.predicate == "height":
            const_parts.append(f"standing {t.object} tall")
        elif t.predicate == "floorCount":
            const_parts.append(f"with {t.object} floors")
        elif t.predicate == "cost":
            const_parts.append(f"at a cost of {t.object}")
        elif t.predicate == "floorArea":
            const_parts.append(f"covering {t.object} floor area")

    if const_parts:
        building_info.append(", ".join(const_parts))

    # Add other information
    for t in main_triples:
        if t.predicate in ["formerName", "bedCount", "numberOfRooms", "tenant", "currentTenants", "governingBody", "leader", "chancellor", "governmentType", "capital", "language", "currency", "ethnicGroup", "origin", "demonym", "keyPerson", "website", "postalCode", "isPartOf", "significantBuilding", "addedToTheNationalRegisterOfHistoricPlaces", "NationalRegisterOfHistoricPlacesReferenceNumber", "foundationPlace", "birthPlace", "deathPlace", "architecture"]:
            if t.predicate == "formerName":
                building_info.append(f"(formerly known as {t.object})")
            elif t.predicate == "isPartOf":
                building_info.append(f"which is part of {t.object}")
            elif t.predicate == "governingBody":
                building_info.append(f"with {main_subject} governed by {t.object}")
            elif t.predicate == "numberOfRooms":
                building_info.append(f"containing {t.object} rooms")
            elif t.predicate == "bedCount":
                building_info.append(f"with {t.object} beds")
            elif t.predicate == "website":
                building_info.append(f"visit {t.object}")
            elif t.predicate == "addedToTheNationalRegisterOfHistoricPlaces":
                building_info.append(f"added to the National Register of Historic Places on {t.object}")
            elif t.predicate == "architecture":
                building_info.append(f"featuring {t.object}")

    # Build the final sentence
    sentence = ", ".join(building_info)

    # Ensure proper capitalization and punctuation
    if sentence:
        sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END
